import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;

public class BankingApplication {

    private Connection connection;

    public BankingApplication(Connection connection) {
        this.connection = connection;
    }

    public synchronized boolean processTransaction(int accountId, double transactionAmount) {
        String selectSQL = "SELECT balance FROM accounts WHERE account_id = ?";
        String updateSQL = "UPDATE accounts SET balance = ? WHERE account_id = ?";
        
        try {
            connection.setAutoCommit(false);
            PreparedStatement selectStmt = connection.prepareStatement(selectSQL);
            selectStmt.setInt(1, accountId);
            ResultSet rs = selectStmt.executeQuery();

            if (rs.next()) {
                double currentBalance = rs.getDouble("balance");

                if (transactionAmount <= 0 || (transactionAmount < 0 && currentBalance + transactionAmount < 0)) {
                    connection.rollback();
                    return false; // Invalid transaction
                }

                double newBalance = currentBalance + transactionAmount;

                PreparedStatement updateStmt = connection.prepareStatement(updateSQL);
                updateStmt.setDouble(1, newBalance);
                updateStmt.setInt(2, accountId);
                updateStmt.executeUpdate();

                connection.commit();
                return true; // Transaction successful
            } else {
                connection.rollback();
                return false; // Account not found
            }
        } catch (SQLException e) {
            try {
                connection.rollback();
            } catch (SQLException rollbackEx) {
                rollbackEx.printStackTrace();
            }
            e.printStackTrace();
            return false; // Transaction failed
        } finally {
            try {
                connection.setAutoCommit(true);
            } catch (SQLException e) {
                e.printStackTrace();
            }
        }
    }
}